#include "../include/memory.h"
#include "../include/alu.h"
#include "../include/clock.h"
#include "../include/cpu.h"
#include <iostream>
#include <fstream> // Required to read files

int main() {
    MemoryManager ram;
    ALU alu;
    Clock systemClock;
    CPU cpu(ram, alu, systemClock);

    // 1. Open the machine code file generated by the assembler
    std::ifstream infile("machine_code.bin", std::ios::binary);
    if (!infile) {
        std::cerr << "FATAL ERROR: Could not open machine_code.bin.\n";
        std::cerr << "Make sure you run the assembler first!\n";
        return 1;
    }

    // 2. Load the binary instructions into the RAM
    uint16_t instr;
    uint16_t addr = 0;
    while (infile.read(reinterpret_cast<char*>(&instr), sizeof(instr))) {
        ram.write(addr, instr);
        addr++;
    }
    std::cout << "--- LOADED " << addr << " INSTRUCTIONS INTO RAM ---\n";

    // 3. Boot up the CPU
    std::cout << "--- CPU BOOT SEQUENCE INITIATED ---\n\n";
    
    // Run the cycle loop (using 100 cycles as a safe maximum for our basic programs)
    for (int i = 0; i < 100; i++) {
        cpu.cycle();
        cpu.printState();
        
        if (cpu.isHalted) {
            break; // Kills the loop the exact cycle the CPU halts
        }
    }

    std::cout << "\n\n--- CPU SHUTDOWN ---\n";
    return 0;
}